import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useToast } from '../context/ToastContext';
import { loginUser } from '../api';

export default function LoginPage() {
  const [form, setForm] = useState({ email: '', password: '', role: 'admin' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const { addToast } = useToast();
  const navigate = useNavigate();

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const { data } = await loginUser(form);

      if (data.role !== form.role) {
        throw new Error(`Account type mismatch. You are registered as ${data.role}.`);
      }

      login(data);
      if (data.role === 'admin') navigate('/admin/dashboard');
      else if (data.role === 'technician') navigate('/technician/dashboard');
      else navigate('/dashboard');
      addToast(`Welcome back!`, 'success');
    } catch (err) {
      addToast(err.message || err.response?.data?.message || 'Login failed. Check credentials.', 'error');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-page auth-page-split">
      <div className="auth-card auth-card-split">

        {/* Left Panel */}
        <div className="auth-split-left">
          <div className="auth-logo-left">
            <img src="/logo.png" alt="Resolve IT Logo" className="auth-logo-left-img" />
            <span>Resolve IT</span>
          </div>
          <div className="auth-illustration">
            <img src="/login_illustration.png" alt="Support Illustration" />
          </div>
        </div>

        {/* Right Panel */}
        <div className="auth-split-right">
          <div className="auth-right-header">
            <h2>Welcome Back!</h2>
            <p>Sign in to continue</p>
          </div>

          <form onSubmit={handleSubmit}>
            <div className="role-tabs">
              <div 
                className={`role-tab ${form.role === 'admin' ? 'active' : ''}`}
                onClick={() => setForm({ ...form, role: 'admin' })}
              >
                Admin
              </div>
              <div 
                className={`role-tab ${form.role === 'technician' ? 'active' : ''}`}
                onClick={() => setForm({ ...form, role: 'technician' })}
              >
                Technician
              </div>
              <div 
                className={`role-tab ${form.role === 'user' ? 'active' : ''}`}
                onClick={() => setForm({ ...form, role: 'user' })}
              >
                User
              </div>
            </div>
            <div className="form-group">
              <label>Email</label>
              <input
                type="email"
                name="email"
                placeholder="Enter your email"
                value={form.email}
                onChange={handleChange}
                required
              />
            </div>
            <div className="form-group">
              <label>Password</label>
              <input
                type="password"
                name="password"
                placeholder="Enter your password"
                value={form.password}
                onChange={handleChange}
                required
              />
            </div>

            <button type="submit" className="btn btn-primary" style={{ width: '100%', justifyContent: 'center', marginTop: 12, padding: '12px', fontSize: '1rem' }} disabled={loading}>
              {loading ? 'Signing in...' : 'Sign In'}
            </button>

            <div style={{ textAlign: 'right', marginTop: 12 }}>
              <a href="#" style={{ fontSize: '0.85rem', color: 'var(--primary)', fontWeight: '600' }} onClick={(e) => e.preventDefault()}>Forgot Password?</a>
            </div>
          </form>

          <p style={{ textAlign: 'center', marginTop: 32, fontSize: '0.875rem', color: '#666', fontWeight: '500' }}>
            Don't have an account? <Link to="/register" style={{ fontWeight: '700' }}>Register</Link>
          </p>
        </div>
      </div>
    </div>
  );
}
